export fn mostConnectedNode(graph: Graph): { node: Node | null; degree: num } {
  if (graph.edges.length === 0) {
    ret { node: null, degree: 0 };
  const degreeMap = new Map<str, num>();
  for (const edge of graph.edges) {
    // Bidirectional degree: each edge contributes +1 to both nodes
    // regardless of direction, counting both as connected
    degreeMap.set(edge.from, (degreeMap.get(edge.from) ?? 0) + 1);
    degreeMap.set(edge.to, (degreeMap.get(edge.to) ?? 0) + 1);
